    private class SendMassEmailExecutor implements Runnable {
        private NUIForm form;
        private HttpSession session;
        private RagicBundle bundle;
        private User user;
        private CustomEmailTemplate template;
        private boolean realSend = false;
    private HttpServletRequest request;

    public SendMassEmailExecutor(HttpSession session, RagicBundle bundle, User user, NUIForm form, CustomEmailTemplate template, boolean realSend, HttpServletRequest request) {
            this.form = form;
            this.session = session;
            this.bundle = bundle;
            this.user = user;
            this.template = template;
            this.realSend = realSend;
            this.request = request;
        }

        public void run() {
            int emailCount = 0;
            int emails = 0;
            int usedEmailQuota = QuotaManager.getInstance().getCurrentCount(form.getApname(), Const.QUOTA_TYPE_EMAIL);
            int totalEmailQuota = QuotaManager.getInstance().getQuota(form.getApname(), Const.QUOTA_TYPE_EMAIL);
            boolean quotaIsOver = false;
            
            IPChecker ipChecker=new IPChecker(request.getRemoteAddr());
            boolean spamIP="AF".equalsIgnoreCase(ipChecker.getContinentCode());
            
            // Check if ghosted
            boolean ifGhosted=SystemData.getInstance().getProperty("GHOSTED_"+form.getApname())!=null || session.getAttribute("GHOSTED")!=null;
            boolean ifContentScreen=false;
            if(template.getSubjectTemplate().toLowerCase().contains("urgent") && template.getContentTemplate().toLowerCase().contains("http")){
                if(ifContentScreen){
                    SystemData.getInstance().setProperty("GHOSTED_"+form.getApname(), "Suspiciouc email content "+ Encoder.formatAsStandardDate(new Date(),true));
                    ifGhosted=true;
                }
                new Mail2().compose("jeff@ragic.com",null,"support@ragic.com","Email Watchdog","Suspicous Email blocked:"+form.getApname(),
                        "Suspicous Email: "+template.getSubjectTemplate()+" - "+template.getContentTemplate()).send();
            }
            try {
                // Get all record root node ids
                final List<Integer> rootNodeIds = new ArrayList<>();
                APIQuery q = new APIQuery(this.form.getApname(), this.form.getPath(), this.form.getFormName());
                q.setUpdateMode();
                NUIFormSet set = NUIFormSetInfo.loadBrowsingFormSet(this.session, this.form.getApname(), this.form.getPath(), this.form.getFormName());
                List<NUIFilter> filters = set.getCurrentFilter();
                for (NUIFilter filter : filters) {
                    q.addFilter(filter.getDomainId(), filter);
                    q.addFetchDomains(filter.getDomainId());
                }
                q.addFetchDomains(form.getRootDomainId());
                APIFullIteration ite = new APIFullIteration(q) {
                    public void entryCustomAction(APIEntry entry, int runningCount) {
                        rootNodeIds.add(entry.getRootNodeId());
                    }
                };
                ite.setReadOnly(true);
                ite.iterate();

                // Check email quota
                // if test to send, add one.
                if(totalEmailQuota < usedEmailQuota + (realSend ? rootNodeIds.size() : 1)) {
                    quotaIsOver = true;
                    return;
                }
                if(realSend && rootNodeIds.size()>1000){
                    Date trialStartDate=Account.getInstance(form.getApname()).getPaymentStatus().getTrialStartDate();
                    if(trialStartDate==null) trialStartDate=new Date(0L);
                    long trialSince=new Date().getTime() - trialStartDate.getTime();
                    if(trialSince<48L*Const.HOUR_MILLI){
                        ifGhosted=true;
                        SystemData.getInstance().setProperty("GHOSTED_"+form.getApname(), "Automatic "+ Encoder.formatAsStandardDate(new Date(),true));
                        new Mail2().compose("jeff@ragic.com",null,"support@ragic.com","Email Watchdog","Auto ghosted account:"+form.getApname(),
                                "Sending mass email in "+(trialSince/Const.HOUR_MILLI)+" hours of getTrialStartDate.").send();
                    }
                }
                
                for (int rootNodeId : rootNodeIds) {
                	if(ifGhosted) {
                        emailCount++;
                        Thread.sleep(10*1000);
                        continue;
                    }
                    try {
                        CustomEmailTemplateHandler handler = CustomEmailTemplateHandlerFactory.getInstance(Const.CUSTOM_EM_TYPE_MASS_EMAIL);
                        String apname = this.form.getApname();
                        String path = this.form.getPath();
                        int sheetIndex = Encoder.parseInt(this.form.getSheetIndex(), -1);
                        handler.addParam("ap", apname);
                        handler.addParam("path", path);
                        handler.addParam("sheetIndex", sheetIndex);
                        handler.addParam("user", user);
                        handler.addParam("bundle", bundle);
                        handler.addParam("nodeId", rootNodeId);

                        // [issue#10040] Only create magic link if needed.
                        String magicRecordLink_basic = com.ragic.s3.util.Util.getServerUrl() + "/" + apname + path + "/" + sheetIndex + "/" + rootNodeId + "?embed&hidetop&embedEntry&rmlc=";
                        if (template.isAttachMagicLinkReadOnly() || template.getContentTemplate().contains("{{MAGIC_RECORD_LINK_READONLY}}")) {
                            String magicRecordLinkCode_readOnly = new MagicRecordLink(apname, path, sheetIndex, rootNodeId).createMagicLink(MagicRecordLink.AccessRight.READONLY);
                            handler.addParam("magicRecordLink_readOnly", magicRecordLink_basic + magicRecordLinkCode_readOnly);
                        }
                        if (template.isAttachMagicLinkEditable() || template.getContentTemplate().contains("{{MAGIC_RECORD_LINK_WRITABLE}}")) {
                            String magicRecordLinkCode_writable = new MagicRecordLink(apname, path, sheetIndex, rootNodeId).createMagicLink(MagicRecordLink.AccessRight.EDITABLE);
                            handler.addParam("magicRecordLink_writable", magicRecordLink_basic + magicRecordLinkCode_writable);
                        }

                        String userName = handler.processCustomEmailTemplateTags("{{USER_NAME}}", CustomEmailTemplateProcessMode.PLAIN_TEXT, bundle);
                        String replyTo = handler.processCustomEmailTemplateTags(template.getReplyToTemplate(), CustomEmailTemplateProcessMode.PLAIN_TEXT, bundle);
                        String recipients = handler.processCustomEmailTemplateTags(template.getRecipientsTemplate(), CustomEmailTemplateProcessMode.PLAIN_TEXT, bundle);
                        String subject = handler.processCustomEmailTemplateTags(template.getSubjectTemplate(), CustomEmailTemplateProcessMode.PLAIN_TEXT, bundle);
                        String content = handler.processCustomEmailTemplateTags(template.getContentTemplate(), CustomEmailTemplateProcessMode.HTML, bundle);

                        List<String> attList = new ArrayList<>();
                        //allowing secretly banning accounts from mass email
                        if(!QuotaManager.getInstance().ifBanMassEmail(form.getApname()) && !spamIP){
                            Mail2 mail = new Mail2();
                            // Compose Email
                            mail.setMassServer();
                            mail.setApname(this.form.getApname());
                            Set<String> attUrls = handler.getDynamicAttachmentLinks(template);
                            for (String url : attUrls) mail.attach(url);
                            CustomEmailTemplateStaticAttachments staticAttachments = handler.getStaticAttachmentFiles(template, bundle);
                            for (Map.Entry<String, File> e : staticAttachments.getAttachmentFiles().entrySet()) {
                                mail.attach(e.getKey(), e.getValue());
                                attList.add(e.getValue().getName());
                            }
                            content += staticAttachments.getErrorMessagesHTML();

                            if (realSend) {
                                // Create email history
                                try {
                                    EmailHistory eh = com.ragic.s3.nui.helper.Util.createEmailHistory(replyTo, recipients, null, subject, content, attList);
                                    eh.save(this.form.getApname(), this.form.getPath(), Encoder.parseInt(this.form.getSheetIndex(), -1), rootNodeId);
                                } catch (Throwable e) {
                                    ExceptionManager.getInstance().processException(e, "create email history" + this.form.getUrl() + "/" + rootNodeId, user);
                                }

                                String receiver = "";
                                int receiverLen = recipients.split(",").length;
                                if(receiverLen > 0){
                                    List<String> receivers = Arrays.asList(recipients.split(","))
                                            .stream().filter(o -> !o.endsWith(".ragic.com")).collect(Collectors.toList());

                                    if(receivers.size() == 1){
                                        receiver = receivers.get(0);
                                    }
                                }

                                int lastSubRootNodeId = new MailTrackerManager().getHistoryMailLastSubRootNodeId(apname, form.getRootDomainId(), rootNodeId);
                                String imgStr;
                                imgStr = "<img src='"+ com.ragic.s3.util.Util.getServerUrl()+ "/sims/mail/trackerMailHistory.jsp?a=" + form.getApname()
                                        + "&rootDomainId=" + new DES().encryptWeb(""+ form.getRootDomainId())
                                        + "&id=" + new DES().encryptWeb(""+ rootNodeId)
                                        + "&subNodeId=" + new DES().encryptWeb(""+ lastSubRootNodeId)
                                        + "&receiver=" + new DES().encryptWeb(receiver)
                                        + "' style='width:1px;height:1px;'/>";
                                content += imgStr;

                            }
                            mail.compose(recipients, null, replyTo, userName, subject, content);
                            
                            if(mail.getToList().size() == 0) {
                                //showing this message is confusing because this is only for 1 record that there is an invalid or empty recipient
                                //https://www.ragic.com/sims/file.jsp?a=tickets&f=27d033QNNI%40%E6%88%AA%E5%9C%96+2021-09-22+%E4%B8%8B%E5%8D%884.20.36.png
                            	//SystemTaskProgress.updateStatus(this.form.getApname(), Const.STP_MASSEMAIL, "Invalid Recipients: " + recipients, emailCount, SystemTaskProgress.Status.ERROR);
                            	continue;
                            }
                            if(!mail.send()) {
                                //showing this message is confusing because this is only for 1 record that there is an invalid or empty recipient
                                //https://www.ragic.com/sims/file.jsp?a=tickets&f=27d033QNNI%40%E6%88%AA%E5%9C%96+2021-09-22+%E4%B8%8B%E5%8D%884.20.36.png
                            	//SystemTaskProgress.updateStatus(this.form.getApname(), Const.STP_MASSEMAIL, "Send fail", emailCount, SystemTaskProgress.Status.ERROR);
                            	continue;
                            }
                            
                            emailCount++;
                            QuotaManager.getInstance().incrementQuota(form.getApname(), Const.QUOTA_TYPE_EMAIL); //add count

                            SystemTaskProgress.setStatus(this.form.getApname(), Const.STP_MASSEMAIL, bundle.getString("customEmail_massEmail_sending", new Object[]{emailCount}), -1, SystemTaskProgress.Status.PROCESSING);
                        }

                        if (!realSend) break; //issue#09159
                    } catch (Throwable e) {
                        ExceptionManager.getInstance().processException(e, "Single record send fail:" + this.form.getUrl() + "/" + rootNodeId, user);
                    } finally {
                    	Thread.sleep(1000);
                    }
                }

            } catch (Throwable e) {
                ExceptionManager.getInstance().processException(e, "General mass email fail " + this.form.getUrl(), user);
            } finally {
                if (quotaIsOver) {
                    String errorMsg = this.bundle.getString("customEmail_massEmail_exceededQuota", new Object[]{totalEmailQuota, usedEmailQuota, totalEmailQuota - usedEmailQuota, emails});
                    SystemTaskProgress.setStatus(this.form.getApname(), Const.STP_MASSEMAIL, errorMsg, -1, SystemTaskProgress.Status.ERROR);
                } else {
                    String successfulMsg = this.bundle.getString("customEmail_massEmail_sendFinished", new Object[]{emailCount, usedEmailQuota + emailCount, totalEmailQuota});
                    SystemTaskProgress.setStatus(this.form.getApname(), Const.STP_MASSEMAIL, successfulMsg, -1, SystemTaskProgress.Status.DONE);
                }
                
                //notify
                if(emailCount>100){
                    new Mail2().compose("jeff@ragic.com",null,"support@ragic.com","Email Watchdog",form.getApname()+" send "+emailCount+" messages"+(ifGhosted?" ghosted":""),
                            "<a href='https://www.ragic.com/"+form.getApname()+"'>"+form.getApname()+"</a>"+
                                    "Count:"+emailCount+"<br>"+
                                    "Subject:"+template.getSubjectTemplate()+"<br>"+
                                    "Content:"+template.getContentTemplate()
                    ).send();
                }
            }
        }
    }

